<template><div class="document-page" v-loading="loading"><div class="document-header"><div><el-button link @click="router.back()"><el-icon><ArrowLeft/></el-icon> 返回</el-button><h1>{{isDecrease?'新增商品报损':'新增库存增加'}}</h1></div><div><el-button @click="router.push('/inventory/adjustments')">取消</el-button><el-button type="primary" :loading="saving" @click="submit">保存草稿</el-button></div></div><el-alert v-if="isDecrease" title="审核后将直接减少仓库库存，请确认报损商品和数量。" type="warning" show-icon :closable="false" class="alert"/><el-card><template #header><div class="section-title"><span>基本信息</span><small>填写调整仓库与业务原因</small></div></template><el-form ref="formRef" :model="form" :rules="rules" label-position="top"><el-row :gutter="20"><el-col :span="8"><el-form-item label="业务日期" prop="adjustmentDate"><el-date-picker v-model="form.adjustmentDate" type="date" value-format="YYYY-MM-DD" style="width:100%"/></el-form-item></el-col><el-col :span="8"><el-form-item label="调整仓库" prop="warehouseId"><el-select v-model="form.warehouseId" style="width:100%"><el-option v-for="w in warehouses" :key="w.value" :label="w.label" :value="w.value"/></el-select></el-form-item></el-col><el-col :span="8"><el-form-item label="调整原因" prop="reason"><el-input v-model="form.reason" maxlength="500" placeholder="如：破损、过期、库存修正"/></el-form-item></el-col><el-col :span="24"><el-form-item label="备注"><el-input v-model="form.remark" type="textarea" :rows="2"/></el-form-item></el-col></el-row></el-form></el-card><el-card class="section-card"><template #header><div class="detail-head"><div class="section-title"><span>调整商品</span><small>{{isDecrease?'数量不能超过可用库存':'请填写参考单位成本'}}</small></div><el-button type="primary" plain @click="addItem">+ 添加商品</el-button></div></template><el-table :data="form.items" border><el-table-column type="index" label="序号" width="60"/><el-table-column label="商品" min-width="260"><template #default="{row}"><el-select v-model="row.productId" filterable style="width:100%"><el-option v-for="p in products" :key="p.value" :value="p.value" :label="p.label"/></el-select></template></el-table-column><el-table-column v-if="isDecrease" label="可用库存" width="110" align="right"><template #default="{row}">{{quantity(stockMap[row.productId])}}</template></el-table-column><el-table-column label="调整数量" width="170"><template #default="{row}"><el-input-number v-model="row.quantity" :min="0.0001" :precision="4" style="width:145px"/></template></el-table-column><el-table-column v-if="!isDecrease" label="单位成本" width="170"><template #default="{row}"><el-input-number v-model="row.unitCost" :min="0" :precision="4" style="width:145px"/></template></el-table-column><el-table-column label="明细原因" min-width="180"><template #default="{row}"><el-input v-model="row.reason"/></template></el-table-column><el-table-column label="操作" width="75"><template #default="{$index}"><el-button link type="danger" @click="form.items.splice($index,1)">删除</el-button></template></el-table-column></el-table><el-empty v-if="!form.items.length" description="暂无商品，请点击右上角添加"/></el-card></div></template>
<script setup lang="ts">import{computed,onMounted,reactive,ref,watch}from'vue';import{useRoute,useRouter}from'vue-router';import{ElMessage}from'element-plus';import{createInventoryAdjustment,getStocks}from'@/api/inventory';import{getProductOptions,getWarehouseOptions}from'@/api/masterdata';const route=useRoute(),router=useRouter(),loading=ref(false),saving=ref(false),formRef=ref(),warehouses=ref<any[]>([]),products=ref<any[]>([]),stockMap=ref<Record<number,number>>({}),isDecrease=computed(()=>String(route.query.type||'DECREASE')==='DECREASE'),form=reactive<any>({adjustmentDate:new Date().toISOString().slice(0,10),warehouseId:null,adjustmentType:isDecrease.value?'DECREASE':'INCREASE',reason:'',remark:'',items:[]}),rules={adjustmentDate:[{required:true,message:'请选择业务日期',trigger:'change'}],warehouseId:[{required:true,message:'请选择调整仓库',trigger:'change'}],reason:[{required:true,message:'请输入调整原因',trigger:'blur'}]};onMounted(async()=>{loading.value=true;try{const[w,p]=await Promise.all([getWarehouseOptions(),getProductOptions()]);warehouses.value=w.data||[];products.value=p.data||[];addItem()}finally{loading.value=false}});watch(()=>form.warehouseId,async id=>{stockMap.value={};if(!id)return;const r=await getStocks({page:1,size:1000,warehouseId:id});stockMap.value=Object.fromEntries((r.data.records||[]).map((s:any)=>[s.productId,Number(s.availableQuantity||0)]))});function addItem(){form.items.push({productId:null,quantity:1,unitCost:0,reason:''})}function quantity(v:any){return Number(v||0).toFixed(4).replace(/\.?0+$/,'')||'0'}async function submit(){if(!await formRef.value.validate().catch(()=>false))return;if(!form.items.length||form.items.some((i:any)=>!i.productId||Number(i.quantity)<=0))return ElMessage.warning('请完整填写至少一条调整商品');if(new Set(form.items.map((i:any)=>i.productId)).size!==form.items.length)return ElMessage.warning('同一商品不能重复添加');if(isDecrease.value&&form.items.some((i:any)=>Number(i.quantity)>Number(stockMap.value[i.productId]||0)))return ElMessage.warning('报损数量不能超过可用库存');saving.value=true;try{const r=await createInventoryAdjustment(form);ElMessage.success('库存调整单已保存');router.replace(`/inventory/adjustments/${r.data.id}`)}finally{saving.value=false}}</script>
<style scoped>.document-page{padding-bottom:24px}.document-header{min-height:66px;display:flex;align-items:center;justify-content:space-between;margin:-16px -20px 16px;padding:0 22px;background:#fff;border-bottom:1px solid #edf0f5}.document-header>div:first-child,.document-header>div:last-child,.section-title,.detail-head{display:flex;align-items:center;gap:10px}.document-header h1{margin:0;font-size:19px}.alert{margin-bottom:14px}.section-card{margin-top:14px}.section-title{gap:12px}.section-title span{font-size:16px;font-weight:600}.section-title small{color:#a1a8b3}.detail-head{justify-content:space-between}</style>
